module deadbeat_controller(  
    input clk,  
    input rst,  
    input [3:0] in,  
    output reg [3:0] out  
);  

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
    if (rst)  
        out <= 4'b0000;  
    else  
        out <= in;  
end  
endmodule
